import{_ as p,c as t,o as e,aK as o}from"./chunks/framework.gpVTZwhR.js";const h=JSON.parse('{"title":"01_最值点就一定是极值点？","description":"","frontmatter":{},"headers":[{"level":2,"title":"1.极值与最值的含义","slug":"_1-极值与最值的含义","link":"#_1-极值与最值的含义","children":[]},{"level":2,"title":"2.最值点一定是极值点吗？","slug":"_2-最值点一定是极值点吗","link":"#_2-最值点一定是极值点吗","children":[]},{"level":2,"title":"3.函数在一个区间内必有最值吗","slug":"_3-函数在一个区间内必有最值吗","link":"#_3-函数在一个区间内必有最值吗","children":[]}],"relativePath":"gaozhong/数学/自己总结/文章/01_最值点就一定是极值点？.md","filePath":"gaozhong/数学/自己总结/文章/01_最值点就一定是极值点？.md","lastUpdated":1740235486000}'),c={name:"gaozhong/数学/自己总结/文章/01_最值点就一定是极值点？.md"};function i(s,a,n,l,r,_){return e(),t("div",null,a[0]||(a[0]=[o('<h1 id="_01-最值点就一定是极值点" tabindex="-1">01_最值点就一定是极值点？ <a class="header-anchor" href="#_01-最值点就一定是极值点" aria-label="Permalink to &quot;01_最值点就一定是极值点？&quot;">​</a></h1><p>在理论和实际中，函数的最值和极值是一个经常接触到的概念。一般来说，最值是全局最优解，极值是局部最优解。但是最值和极值具体的不同之处你是否都清楚呢？小编在本文将会详细阐述。</p><h2 id="_1-极值与最值的含义" tabindex="-1">1.极值与最值的含义 <a class="header-anchor" href="#_1-极值与最值的含义" aria-label="Permalink to &quot;1.极值与最值的含义&quot;">​</a></h2><p>首先，大家一定要清楚极值与最值的区别。</p><p>谈论函数的极值与最值，都是基于一个区间来说的，这个区间可以是开区间、闭区间，也可以是半开半闭区间。</p><p>要理解极值与最值的区别，最好的方法就是结合图形去看，大家不妨看看图 1 中的函数曲线。</p><img src="https://my-course-public.oss-cn-shanghai.aliyuncs.com/picgo/picgo-2025-02-20-07-45-25.png" alt="picgo-2025-02-20-07-45-25"><p>图 1.极值点判断图</p><p>你能看出函数 f(x) 在闭区间[a, b]上最值点和极值点的数量情况吗？</p><p>最值点容易判断，最大值点 1 个，最小值点 1 个。最大值就是函数在一个区间内所能<strong>取到</strong>的最大值，最小值就是函数在一个区间内所能取到的最小值。一定要记住，小编在这里用到了“<strong>取到</strong>”两个字。对于图 1 的函数 f(x)，f(x) 在点 x0 处取得最大值，在 x1 处取得最小值，相应的，x0 称为最大值点，x1 称为最小值点。</p><p>那么极值点的数量情况呢？</p><p>在统计极值点数量之前，小编先把极值的定义给出来，如下所示：</p><img src="https://my-course-public.oss-cn-shanghai.aliyuncs.com/picgo/picgo-2025-02-20-07-45-59.png" alt="picgo-2025-02-20-07-45-59"><p>根据极值的定义，显然图 1 中至少有 3 个极大值点（图 2 中红色的点）和 2 个极小值点（图 2 中绿色的点）！但是区间的端点呢，也就是 x=a,x=b 是不是极值点呢？</p><img src="https://my-course-public.oss-cn-shanghai.aliyuncs.com/picgo/picgo-2025-02-20-07-46-26.png" alt="picgo-2025-02-20-07-46-26"><p>图 2.函数 f(x) 极值点标注图</p><p>大家一定要记住，区间的端点不是极值点，因为，如果 x=c 是极值点，那么点 c 的函数值 f(c) 必须是点 c 的左、右两侧的局部区域的唯一最值。比如图 2 中的端点 a，f(a) 只是点 a 的右侧局部区域的唯一最小值，因此 x=c 不是极值点。</p><p>所以图 1 中函数 f(x) 就只有 3 个极大值点和 2 个极小值点。</p><h2 id="_2-最值点一定是极值点吗" tabindex="-1">2.最值点一定是极值点吗？ <a class="header-anchor" href="#_2-最值点一定是极值点吗" aria-label="Permalink to &quot;2.最值点一定是极值点吗？&quot;">​</a></h2><p>显然不是。</p><p>不妨看看下图 3。</p><img src="https://my-course-public.oss-cn-shanghai.aliyuncs.com/picgo/picgo-2025-02-20-07-47-01.png" alt="picgo-2025-02-20-07-47-01"><p>图 3.最值点不一定是极值点示意图</p><p>在左图中，f(x) 在闭区间[a,b]上存在最大值，区间[c, d]之间的任意一点都是最大值点。但是 f(x) 在闭区间[a,b]上不存在极大值，因为函数在区间[c,d]内的任意一点都不满足极值的定义，即左右两侧局部区域的唯一最值。</p><p>在右图中，函数 g(x) 在闭区间[a,b]上存在最值，两个端点分别为最大值点和最小值点。但是 g(x) 在闭区间上同样不存在极值点。</p><h2 id="_3-函数在一个区间内必有最值吗" tabindex="-1">3.函数在一个区间内必有最值吗 <a class="header-anchor" href="#_3-函数在一个区间内必有最值吗" aria-label="Permalink to &quot;3.函数在一个区间内必有最值吗&quot;">​</a></h2><p>不是，只有满足两个条件，函数在一个区间内才必有最大值和最小值：闭区间，连续。即连续函数在闭区间内必有最大值和最小值，这就是有界性与最大值最小值定理的部分内容。</p><p>一个很简单的例子，就是函数 f(x)=tanx 在开区间 (-π/2, π/2) 内虽然连续，但是没有最值。</p>',28)]))}const d=p(c,[["render",i]]);export{h as __pageData,d as default};
